/*!
 * AI 防詐盾牌 Socket.IO 輕量展示備援版。
 * 這不是官方 Socket.IO client；Dashboard 會偵測到此 shim 並改用資料更新模式。
 */
(function () {
  "use strict";
  function io() {
    const handlers = {};
    const socket = {
      connected: false,
      on(eventName, handler) {
        handlers[eventName] = handler;
        if (eventName === "connect_error") {
          setTimeout(() => {
            try { handler(new Error("Socket.IO client shim fallback")); } catch (e) {}
          }, 0);
        }
        return socket;
      },
      emit() { return socket; },
      disconnect() {
        socket.connected = false;
        if (typeof handlers.disconnect === "function") {
          try { handlers.disconnect("shim-disconnect"); } catch (e) {}
        }
        return socket;
      }
    };
    return socket;
  }
  io.__AI_SHIELD_SOCKET_IO_SHIM__ = true;
  window.io = window.io || io;
})();
